import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ItemResponse {
  studentId: string;
  responses: Record<string, string>; // itemID -> answer (e.g., 'A')
  totalScore: number;
}

export interface ItemAnalysis {
  itemId: string;
  correctAnswer: string;
  difficultyIndex: number; // p-value (0 to 1)
  discriminationIndex: number; // D index (-1 to 1)
  distractorCounts: Record<string, number>;
  distractorFrequencies: Record<string, number>;
  flags: string[];
  pointBiserial?: number;
}

export interface TestReliability {
  kr20: number;
  meanScore: number;
  stdDev: number;
  itemCount: number;
  studentCount: number;
}

export interface AnalysisResults {
  items: ItemAnalysis[];
  reliability: TestReliability;
  rawResponses: ItemResponse[];
}

export interface Thresholds {
  difficulty: { min: number; max: number };
  discrimination: { min: number };
}

import { Thresholds } from './types';

export const DEFAULT_THRESHOLDS: Thresholds = {
  difficulty: { min: 0.3, max: 0.8 }, // 0.3 to 0.8 is generally optimal
  discrimination: { min: 0.2 },       // Above 0.2 is acceptable, above 0.3 is good
};

export const SAMPLE_CSV_TEMPLATE = `StudentID,Q1,Q2,Q3,Q4,Q5
KEY,A,B,C,D,A
Student1,A,B,C,D,A
Student2,A,C,C,B,A
Student3,B,B,C,D,C
Student4,A,B,A,D,A
Student5,C,B,C,A,B
Student6,A,B,C,D,A`;

import { ItemResponse, ItemAnalysis, TestReliability, AnalysisResults, Thresholds } from '../types';

/**
 * Main service to process CSV data into psychometric insights.
 * Expects CSV as a 2D array: [header, key, student1, student2, ...]
 */
export const analyzeAssessment = (
  data: string[][],
  thresholds: Thresholds
): AnalysisResults => {
  if (data.length < 3) throw new Error("Insufficient data: Need header, key, and at least one student.");

  const headers = data[0];
  const keyRow = data[1];
  const itemIds = headers.slice(1); // Skip StudentID column
  const answerKey: Record<string, string> = {};
  itemIds.forEach((id, idx) => {
    answerKey[id] = keyRow[idx + 1];
  });

  const studentRows = data.slice(2);
  const studentResponses: ItemResponse[] = studentRows.map((row) => {
    const studentId = row[0];
    const responses: Record<string, string> = {};
    let score = 0;
    itemIds.forEach((id, idx) => {
      const answer = row[idx + 1];
      responses[id] = answer;
      if (answer === answerKey[id]) score++;
    });
    return { studentId, responses, totalScore: score };
  });

  const studentCount = studentResponses.length;
  const itemCount = itemIds.length;

  // Sort students by total score for discrimination analysis (Top/Bottom 27%)
  const sortedStudents = [...studentResponses].sort((a, b) => b.totalScore - a.totalScore);
  const groupSize = Math.max(1, Math.floor(studentCount * 0.27));
  const topGroup = sortedStudents.slice(0, groupSize);
  const bottomGroup = sortedStudents.slice(-groupSize);

  // Item Analysis
  const items: ItemAnalysis[] = itemIds.map((itemId) => {
    const correct = answerKey[itemId];
    let correctCount = 0;
    const distractorCounts: Record<string, number> = {};

    studentResponses.forEach((s) => {
      const resp = s.responses[itemId];
      if (resp === correct) correctCount++;
      distractorCounts[resp] = (distractorCounts[resp] || 0) + 1;
    });

    const difficultyIndex = correctCount / studentCount;

    // Discrimination (D = pTop - pBottom)
    const topCorrect = topGroup.filter(s => s.responses[itemId] === correct).length;
    const bottomCorrect = bottomGroup.filter(s => s.responses[itemId] === correct).length;
    const discriminationIndex = (topCorrect - bottomCorrect) / groupSize;

    // Flags
    const flags: string[] = [];
    if (difficultyIndex < thresholds.difficulty.min) flags.push("Too Difficult");
    if (difficultyIndex > thresholds.difficulty.max) flags.push("Too Easy");
    if (discriminationIndex < thresholds.discrimination.min) flags.push("Poor Discrimination");
    if (discriminationIndex < 0) flags.push("Negative Discrimination");

    // Distractor Frequency (%)
    const distractorFrequencies: Record<string, number> = {};
    Object.keys(distractorCounts).forEach(opt => {
      distractorFrequencies[opt] = distractorCounts[opt] / studentCount;
    });

    return {
      itemId,
      correctAnswer: correct,
      difficultyIndex,
      discriminationIndex,
      distractorCounts,
      distractorFrequencies,
      flags
    };
  });

  // Test Reliability (KR-20)
  const scores = studentResponses.map(s => s.totalScore);
  const meanScore = scores.reduce((a, b) => a + b, 0) / studentCount;
  const variance = scores.reduce((a, b) => a + Math.pow(b - meanScore, 2), 0) / studentCount;

  // Sum of p*q for all items
  const sumPQ = items.reduce((sum, item) => {
    const p = item.difficultyIndex;
    const q = 1 - p;
    return sum + (p * q);
  }, 0);

  const kr20 = (itemCount / (itemCount - 1)) * (1 - (sumPQ / variance));

  const reliability: TestReliability = {
    kr20: isNaN(kr20) ? 0 : kr20,
    meanScore,
    stdDev: Math.sqrt(variance),
    itemCount,
    studentCount
  };

  return { items, reliability, rawResponses: studentResponses };
};

import { GoogleGenAI } from "@google/genai";
import { AnalysisResults } from "../types";

export const getAIInsights = async (results: AnalysisResults): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const flaggedItems = results.items.filter(i => i.flags.length > 0);
  const summary = {
    totalItems: results.reliability.itemCount,
    studentCount: results.reliability.studentCount,
    reliability: results.reliability.kr20.toFixed(2),
    flaggedCount: flaggedItems.length,
    meanScore: results.reliability.meanScore.toFixed(2),
    troubleItems: flaggedItems.map(i => ({
      id: i.itemId,
      flags: i.flags.join(", "),
      difficulty: i.difficultyIndex.toFixed(2),
      discrimination: i.discriminationIndex.toFixed(2)
    }))
  };

  const prompt = `
    Act as a senior Psychometrician. Analyze the following MCQ test results and provide a professional, concise executive summary.
    Identify if the test is reliable, which items are candidates for deletion or revision, and overall recommendations.

    Data Summary:
    ${JSON.stringify(summary, null, 2)}

    Format your response in Markdown. Focus on actionable insights.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating AI insights. Please check your API usage.";
  }
};

import React, { useRef } from 'react';
import { SAMPLE_CSV_TEMPLATE } from '../constants';

interface FileUploadProps {
  onDataLoaded: (data: string[][]) => void;
  onError: (msg: string) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataLoaded, onError }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (!content) return;

      const rows = content.split(/\r?\n/).filter(line => line.trim() !== "").map(line => 
        line.split(',').map(cell => cell.trim())
      );

      if (rows.length < 3) {
        onError("Invalid file structure. Need at least Header, Key, and 1 Student row.");
        return;
      }
      onDataLoaded(rows);
    };
    reader.onerror = () => onError("Error reading file.");
    reader.readAsText(file);
  };

  const downloadTemplate = () => {
    const blob = new Blob([SAMPLE_CSV_TEMPLATE], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'mcq_template.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
      <div className="max-w-xl mx-auto text-center">
        <div className="mb-6 flex justify-center">
          <div className="bg-blue-50 p-4 rounded-full">
            <svg className="w-12 h-12 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
          </div>
        </div>
        <h2 className="text-2xl font-bold text-slate-900 mb-2">Upload Assessment Data</h2>
        <p className="text-slate-500 mb-8">Select a CSV file containing student responses and the answer key.</p>

        <div className="space-y-4">
          <label className="relative group cursor-pointer block">
            <div className="flex items-center justify-center border-2 border-dashed border-slate-300 group-hover:border-blue-500 bg-slate-50 group-hover:bg-blue-50 transition-all duration-200 py-10 rounded-xl">
              <span className="text-slate-600 font-medium group-hover:text-blue-600">Choose file or drag here</span>
            </div>
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileUpload}
              className="hidden" 
              accept=".csv"
            />
          </label>

          <div className="flex justify-center gap-4 text-sm font-medium">
            <button 
              onClick={downloadTemplate}
              className="text-blue-600 hover:text-blue-800 transition-colors"
            >
              Download Template CSV
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FileUpload;

import React from 'react';
import { TestReliability } from '../types';

interface Props {
  reliability: TestReliability;
  flaggedCount: number;
}

const StatCard: React.FC<{ label: string; value: string | number; subtext?: string; color: string }> = ({ label, value, subtext, color }) => (
  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
    <p className="text-sm font-medium text-slate-500 mb-1">{label}</p>
    <div className={`text-3xl font-bold ${color}`}>{value}</div>
    {subtext && <p className="text-xs text-slate-400 mt-2">{subtext}</p>}
  </div>
);

const DashboardOverview: React.FC<Props> = ({ reliability, flaggedCount }) => {
  const getReliabilityColor = (val: number) => {
    if (val >= 0.8) return 'text-emerald-600';
    if (val >= 0.6) return 'text-amber-600';
    return 'text-rose-600';
  };

  const getReliabilityText = (val: number) => {
    if (val >= 0.8) return 'Excellent';
    if (val >= 0.7) return 'Good';
    if (val >= 0.6) return 'Acceptable';
    return 'Poor';
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
      <StatCard 
        label="Test Reliability (KR-20)" 
        value={reliability.kr20.toFixed(3)} 
        subtext={`${getReliabilityText(reliability.kr20)} internal consistency`}
        color={getReliabilityColor(reliability.kr20)}
      />
      <StatCard 
        label="Average Score" 
        value={reliability.meanScore.toFixed(1)} 
        subtext={`Out of ${reliability.itemCount} points`}
        color="text-slate-900"
      />
      <StatCard 
        label="Students Tested" 
        value={reliability.studentCount} 
        subtext="Total participants"
        color="text-slate-900"
      />
      <StatCard 
        label="Flagged Items" 
        value={flaggedCount} 
        subtext="Need review or revision"
        color={flaggedCount > 0 ? 'text-rose-600' : 'text-emerald-600'}
      />
    </div>
  );
};

export default DashboardOverview;

