export default ItemTable;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, ZAxis, Cell } from 'recharts';
import { ItemAnalysis } from '../types';

interface Props {
  items: ItemAnalysis[];
}

const Visualizations: React.FC<Props> = ({ items }) => {
  // Prep data for difficulty histogram
  const diffBins = [
    { name: '0.0-0.2', count: 0 },
    { name: '0.2-0.4', count: 0 },
    { name: '0.4-0.6', count: 0 },
    { name: '0.6-0.8', count: 0 },
    { name: '0.8-1.0', count: 0 },
  ];

  items.forEach(item => {
    if (item.difficultyIndex < 0.2) diffBins[0].count++;
    else if (item.difficultyIndex < 0.4) diffBins[1].count++;
    else if (item.difficultyIndex < 0.6) diffBins[2].count++;
    else if (item.difficultyIndex < 0.8) diffBins[3].count++;
    else diffBins[4].count++;
  });

  const scatterData = items.map(item => ({
    x: item.difficultyIndex,
    y: item.discriminationIndex,
    id: item.itemId
  }));

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-bold text-slate-900 mb-6">Difficulty Distribution</h3>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={diffBins}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip 
                cursor={{fill: '#f1f5f9'}}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
        <p className="text-xs text-slate-400 mt-4 text-center italic">Optimal difficulty is usually between 0.3 and 0.8</p>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-bold text-slate-900 mb-6">Discrimination vs. Difficulty</h3>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
              <CartesianGrid />
              <XAxis type="number" dataKey="x" name="Difficulty" unit="p" domain={[0, 1]} />
              <YAxis type="number" dataKey="y" name="Discrimination" unit="D" domain={[-0.5, 1]} />
              <ZAxis range={[60, 400]} />
              <Tooltip cursor={{ strokeDasharray: '3 3' }} />
              <Scatter name="Items" data={scatterData} fill="#8884d8">
                {scatterData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.y < 0.2 ? '#f43f5e' : '#10b981'} />
                ))}
              </Scatter>
            </ScatterChart>
          </ResponsiveContainer>
        </div>
        <p className="text-xs text-slate-400 mt-4 text-center italic">Target high discrimination (Top Right) across all difficulty levels</p>
      </div>
    </div>
  );
};

export default Visualizations;

import React, { useState, useEffect } from 'react';
import { AnalysisResults, Thresholds } from './types';
import { DEFAULT_THRESHOLDS } from './constants';
import { analyzeAssessment } from './services/psychometricService';
import { getAIInsights } from './services/geminiService';
import FileUpload from './components/FileUpload';
import DashboardOverview from './components/DashboardOverview';
import ItemTable from './components/ItemTable';
import Visualizations from './components/Visualizations';

const App: React.FC = () => {
  const [results, setResults] = useState<AnalysisResults | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [thresholds, setThresholds] = useState<Thresholds>(DEFAULT_THRESHOLDS);

  const handleDataLoaded = (data: string[][]) => {
    try {
      const analysis = analyzeAssessment(data, thresholds);
      setResults(analysis);
      setError(null);
      setAiInsights(null); // Reset AI insights for new data
    } catch (err: any) {
      setError(err.message || "An error occurred during analysis.");
    }
  };

  const generateInsights = async () => {
    if (!results) return;
    setLoadingAI(true);
    const insights = await getAIInsights(results);
    setAiInsights(insights);
    setLoadingAI(false);
  };

  const exportResults = () => {
    if (!results) return;
    const csvContent = "data:text/csv;charset=utf-8," + 
      "ItemID,Difficulty,Discrimination,Flags\n" + 
      results.items.map(item => `${item.itemId},${item.difficultyIndex},${item.discriminationIndex},"${item.flags.join(", ")}"`).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "mcq_analysis_report.csv");
    document.body.appendChild(link);
    link.click();
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <nav className="bg-white border-b border-slate-200 px-6 py-4 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
            </div>
            <h1 className="text-xl font-extrabold text-slate-900 tracking-tight">MCQ Analyzer Pro</h1>
          </div>
          <div className="flex gap-4">
            {results && (
              <button 
                onClick={() => setResults(null)}
                className="text-sm font-semibold text-slate-500 hover:text-slate-900"
              >
                Reset
              </button>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 pt-8">
        {!results ? (
          <div className="max-w-2xl mx-auto mt-12">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-4">Validate Your Assessments</h2>
              <p className="text-lg text-slate-600">Empower your testing with enterprise-grade psychometric analytics. Instant difficulty, discrimination, and reliability reporting.</p>
            </div>
            <FileUpload onDataLoaded={handleDataLoaded} onError={setError} />
            {error && (
              <div className="mt-6 bg-rose-50 border border-rose-200 text-rose-700 p-4 rounded-xl flex items-center gap-3">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                {error}
              </div>
            )}
          </div>
        ) : (
          <div className="animate-in fade-in duration-500">
            {/* Action Bar */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">Assessment Dashboard</h2>
                <p className="text-slate-500">Analysis completed for {results.reliability.itemCount} items.</p>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={exportResults}
                  className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm font-semibold text-slate-700 hover:bg-slate-50 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  Export Report
                </button>
                <button 
                  onClick={generateInsights}
                  disabled={loadingAI}
                  className="flex items-center gap-2 px-4 py-2 bg-blue-600 rounded-lg text-sm font-semibold text-white hover:bg-blue-700 transition-colors disabled:opacity-50"
                >
                  {loadingAI ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      Thinking...
                    </span>
