import React from 'react';
import { Thresholds } from '../types';

interface Props {
  thresholds: Thresholds;
  onThresholdChange: (newThresholds: Thresholds) => void;
}

const ThresholdSettings: React.FC<Props> = ({ thresholds, onThresholdChange }) => {
  const handleChange = (category: 'difficulty' | 'discrimination', key: string, value: number) => {
    const updated = { ...thresholds };
    if (category === 'difficulty') {
      (updated.difficulty as any)[key] = value;
    } else {
      (updated.discrimination as any)[key] = value;
    }
    onThresholdChange(updated);
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm mb-8 animate-in slide-in-from-top-2 duration-300">
      <div className="flex items-center gap-2 mb-4">
