import { ItemResponse, ItemAnalysis, TestReliability, AnalysisResults, Thresholds } from '../types';

/**
 * Main service to process CSV data into psychometric insights.
 * Expects CSV as a 2D array: [header, key, student1, student2, ...]
 */
export const analyzeAssessment = (
  data: string[][],
  thresholds: Thresholds
): AnalysisResults => {
  if (data.length < 3) throw new Error("Insufficient data: Need header, key, and at least one student.");

  const headers = data[0];

  // Identify valid question columns (columns > 0 that have a non-empty header)
  const validColumnIndices = headers
    .map((h, i) => (i > 0 && h.trim() !== "" ? i : -1))
    .filter(i => i !== -1);

  if (validColumnIndices.length === 0) {
    throw new Error("No question columns identified. Ensure your CSV has headers for each question.");
  }

  const itemIds = validColumnIndices.map(idx => headers[idx]);
  const keyRow = data[1];

  const answerKey: Record<string, string> = {};
  validColumnIndices.forEach((colIdx, listIdx) => {
    const id = itemIds[listIdx];
    answerKey[id] = keyRow[colIdx] || "";
  });

  const studentRows = data.slice(2);
  const studentResponses: ItemResponse[] = studentRows.map((row) => {
    const studentId = row[0] || "Unknown";
    const responses: Record<string, string> = {};
    let score = 0;

    validColumnIndices.forEach((colIdx, listIdx) => {
      const id = itemIds[listIdx];
      const answer = row[colIdx] || "";
      responses[id] = answer;
      if (answer !== "" && answer === answerKey[id]) {
        score++;
      }
    });

    return { studentId, responses, totalScore: score };
  });

  const studentCount = studentResponses.length;
  const itemCount = itemIds.length;

  // Sort students by total score for discrimination analysis (Top/Bottom 27%)
  const sortedStudents = [...studentResponses].sort((a, b) => b.totalScore - a.totalScore);
  const groupSize = Math.max(1, Math.floor(studentCount * 0.27));
  const topGroup = sortedStudents.slice(0, groupSize);
  const bottomGroup = sortedStudents.slice(-groupSize);

  // Item Analysis
  const items: ItemAnalysis[] = itemIds.map((itemId) => {
    const correct = answerKey[itemId];
    let correctCount = 0;
    const distractorCounts: Record<string, number> = {};

    studentResponses.forEach((s) => {
      const resp = s.responses[itemId];
      if (resp !== "" && resp === correct) correctCount++;
      if (resp !== "") {
        distractorCounts[resp] = (distractorCounts[resp] || 0) + 1;
      }
    });

    const difficultyIndex = studentCount > 0 ? correctCount / studentCount : 0;

    // Discrimination (D = pTop - pBottom)
    const topCorrect = topGroup.filter(s => s.responses[itemId] === correct).length;
    const bottomCorrect = bottomGroup.filter(s => s.responses[itemId] === correct).length;
    const discriminationIndex = (topCorrect - bottomCorrect) / groupSize;

    // Flags
    const flags: string[] = [];
    if (difficultyIndex < thresholds.difficulty.min) flags.push("Too Difficult");
    if (difficultyIndex > thresholds.difficulty.max) flags.push("Too Easy");
    if (discriminationIndex < thresholds.discrimination.min) flags.push("Poor Discrimination");
    if (discriminationIndex < 0) flags.push("Negative Discrimination");

    // Distractor Frequency (%)
    const distractorFrequencies: Record<string, number> = {};
    Object.keys(distractorCounts).forEach(opt => {
      distractorFrequencies[opt] = distractorCounts[opt] / studentCount;
    });

    return {
      itemId,
      correctAnswer: correct,
      difficultyIndex,
      discriminationIndex,
      distractorCounts,
      distractorFrequencies,
      flags
    };
  });

  // Test Reliability (KR-20)
  const scores = studentResponses.map(s => s.totalScore);
  const meanScore = studentCount > 0 ? scores.reduce((a, b) => a + b, 0) / studentCount : 0;
  const variance = studentCount > 0 ? scores.reduce((a, b) => a + Math.pow(b - meanScore, 2), 0) / studentCount : 0;

  // Sum of p*q for all items
  const sumPQ = items.reduce((sum, item) => {
    const p = item.difficultyIndex;
    const q = 1 - p;
    return sum + (p * q);
  }, 0);

  // Avoid division by zero if variance is 0 or only 1 item
  const kr20 = (itemCount > 1 && variance > 0) 
    ? (itemCount / (itemCount - 1)) * (1 - (sumPQ / variance))
    : 0;

  const reliability: TestReliability = {
    kr20: isNaN(kr20) ? 0 : kr20,
    meanScore,
    stdDev: Math.sqrt(variance),
    itemCount,
    studentCount
  };

  return { items, reliability, rawResponses: studentResponses };
};

import React, { useRef } from 'react';
import { SAMPLE_CSV_TEMPLATE } from '../constants';

interface FileUploadProps {
  onDataLoaded: (data: string[][]) => void;
  onError: (msg: string) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataLoaded, onError }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (!content) return;

      // Split into lines, filter empty, then split columns and trim
      const rows = content
        .split(/\r?\n/)
        .map(line => line.trim())
        .filter(line => line !== "")
        .map(line => line.split(',').map(cell => cell.trim()));

      if (rows.length < 3) {
        onError("Invalid file structure. Need at least Header, Key, and 1 Student row.");
        return;
      }
      onDataLoaded(rows);
    };
    reader.onerror = () => onError("Error reading file.");
    reader.readAsText(file);
  };

  const downloadTemplate = () => {
    const blob = new Blob([SAMPLE_CSV_TEMPLATE], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'mcq_template.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
      <div className="max-w-xl mx-auto text-center">
        <div className="mb-6 flex justify-center">
          <div className="bg-blue-50 p-4 rounded-full">
            <svg className="w-12 h-12 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
          </div>
        </div>
        <h2 className="text-2xl font-bold text-slate-900 mb-2">Upload Assessment Data</h2>
        <p className="text-slate-500 mb-8">Select a CSV file containing student responses and the answer key.</p>

        <div className="space-y-4">
          <label className="relative group cursor-pointer block">
            <div className="flex items-center justify-center border-2 border-dashed border-slate-300 group-hover:border-blue-500 bg-slate-50 group-hover:bg-blue-50 transition-all duration-200 py-10 rounded-xl">
              <span className="text-slate-600 font-medium group-hover:text-blue-600">Choose file or drag here</span>
            </div>
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileUpload}
              className="hidden" 
              accept=".csv"
            />
          </label>

          <div className="flex justify-center gap-4 text-sm font-medium">
            <button 
              onClick={downloadTemplate}
              className="text-blue-600 hover:text-blue-800 transition-colors"
            >
              Download Template CSV
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FileUpload;

